import{_ as e,o as t,c as a,a3 as s}from"./chunks/framework.LBeL10WQ.js";const u=JSON.parse('{"title":"3. Validation & Broadcast","description":"","frontmatter":{"title":"3. Validation & Broadcast"},"headers":[],"relativePath":"en/advertisers/dedicated-email/3-validation-diffusion.md","filePath":"en/advertisers/dedicated-email/3-validation-diffusion.md"}'),o={name:"en/advertisers/dedicated-email/3-validation-diffusion.md"};function n(d,i,r,c,l,p){return t(),a("div",null,[...i[0]||(i[0]=[s('<h1 id="step-3-validation-and-broadcast" tabindex="-1">Step 3: Validation and Broadcast <a class="header-anchor" href="#step-3-validation-and-broadcast" aria-label="Permalink to &quot;Step 3: Validation and Broadcast&quot;">​</a></h1><p>Creation is complete. Only the Proof (BAT) needs to be validated to authorize sending.</p><hr><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Tracking Configuration</h3><p>This step is invisible to you. The getinside team and the distributor embed the open pixels and tracked redirection links.</p><p><strong>Reminder:</strong> your links are dynamic — you can change the destination URL at any time in the <strong>&quot;Configuration and Tracking&quot;</strong> tab, even after validation.</p></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Receiving the Proof (BAT)</h3><p>As soon as the distributor has finalized the email and getinside has technically verified it, you receive an email notification.</p><p>You can access a <strong>static preview</strong> of the campaign to check adherence to the brief (offer, visuals, wording).</p></div></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Your Validation (Action Required)</h3><p>If the creative satisfies you, you must validate on the platform to unblock the sending.</p></div></div><div class="warning custom-block"><p class="custom-block-title">Required action to unblock sending</p><ol><li>Log in to <a href="https://app.getinside.media/" target="_blank">app.getinside.media</a>.</li><li>Open the relevant campaign.</li><li>Click the <strong>&quot;Validate campaign&quot;</strong> button.</li></ol><p>Until you validate, the campaign remains blocked — it will not be broadcast.</p></div><div class="gi-step"><div class="gi-step-num done">4</div><div class="gi-step-body"><h3>Broadcast</h3><p>Once both validations are recorded (yours + the distributor&#39;s), the campaign is scheduled and sent to the targeted audience.</p><p>Track statistics (opens, clicks) in real-time from your dashboard.</p></div></div><div class="tip custom-block"><p class="custom-block-title">Resend to non-openers</p><p>Some distributors offer to automatically resend the campaign to subscribers who did not open the email during the first send. Ask for it during the brief to maximize coverage.</p></div>',9)])])}const v=e(o,[["render",n]]);export{u as __pageData,v as default};
